func TestPartialObjectMetadataLogging(t *testing.T) {
	// Simulate what happens when PartialObjectMetadata is used with Kind source
	// The issue: logging shows "*v1.PartialObjectMetadata" without the actual kind

	metaObj := &metav1.PartialObjectMetadata{}
	metaObj.SetGroupVersionKind(schema.GroupVersionKind{
