	desiredFormat := fmt.Sprintf("kind source: *v1.PartialObjectMetadata(%s)", gvk.String())
	t.Logf("Desired format: %s", desiredFormat)

	// Verify we can extract GVK from PartialObjectMetadata
	if gvk.Kind == "" {
		t.Error("GVK should not be empty for a properly initialized PartialObjectMetadata")
