// objectTypeDescription returns a human-readable description for the type of an
// object being watched. For PartialObjectMetadata, it includes the underlying
// GroupVersionKind to make logs more useful for debugging.
func objectTypeDescription(obj runtime.Object, gvk schema.GroupVersionKind) string {
	switch obj.(type) {
	case *metav1.PartialObjectMetadata, *metav1.PartialObjectMetadataList:
		if gvk.Kind != "" {
			return fmt.Sprintf("%T(%s)", obj, gvk.String())
		}
